sql:
SELECT name, youtube_view_count
FROM vtubers
ORDER BY youtube_view_count DESC;

SELECT name, country
FROM vtubers
ORDER BY youtube_subscriber_count DESC;

SELECT vtuber_id, average_viewer_count, total_minutes_watched
FROM twitch_stats
WHERE average_viewer_count > 150;

SELECT vtuber_id, total_videos, total_watch_time_minutes
FROM youtube_stats
WHERE subscriber_growth_rate > 0.03;

SELECT name
FROM vtubers
WHERE youtube_subscriber_count = (SELECT MAX(youtube_subscriber_count) FROM vtubers);

SELECT name, youtube_subscriber_count
FROM vtubers
WHERE management_team = 'HoloLive';

SELECT vtuber_id, AVG(youtube_view_count) AS average_views
FROM vtubers
GROUP BY vtuber_id;
